# ============================================================
#  THEME & CSS
# ============================================================

app_theme <- bs_theme(
  version      = 5,
  bg           = "#faf7f2",
  fg           = "#2d2520",
  primary      = "#d4380d",
  secondary    = "#8c7355",
  success      = "#27ae60",
  info         = "#2980b9",
  warning      = "#e67e22",
  "navbar-bg"  = "#1a1612",
  base_font    = font_google("DM Sans"),
  heading_font = font_google("DM Serif Display"),
  code_font    = font_google("Space Mono")
)

app_css <- "
  body { background:#faf7f2; font-size:14px; }
  h1,h2,h3,h4,h5 { font-family:\'DM Serif Display\',serif; font-weight:400; }
  .navbar { border-bottom:3px solid #d4380d !important; }
  .nav-link { font-size:.74rem !important; letter-spacing:.07em; text-transform:uppercase; }
  .hero-wrap {
    background:#1a1612; color:#f0ede6; padding:3rem 2rem 2.5rem;
    background-image:
      repeating-linear-gradient(0deg,transparent,transparent 39px,rgba(255,255,255,.025) 39px,rgba(255,255,255,.025) 40px),
      repeating-linear-gradient(90deg,transparent,transparent 39px,rgba(255,255,255,.025) 39px,rgba(255,255,255,.025) 40px);
  }
  .hero-eyebrow { font-family:\'Space Mono\',monospace; font-size:.62rem; letter-spacing:.18em;
    text-transform:uppercase; color:#e67e22; border:1px solid rgba(230,126,34,.4);
    display:inline-block; padding:.25rem .7rem; margin-bottom:1rem; }
  .hero-title { font-family:\'DM Serif Display\',serif; font-size:clamp(2.2rem,5vw,4.5rem);
    line-height:.95; letter-spacing:-.02em; margin-bottom:.8rem; }
  .hero-title em { color:#e67e22; font-style:italic; }
  .hero-desc { color:rgba(240,237,230,.6); font-size:.88rem; line-height:1.75; max-width:560px; }
  .kpi-box { background:#1a1612; color:#f0ede6; padding:1.4rem 1.6rem; border-top:3px solid #d4380d; }
  .kpi-num { font-family:\'DM Serif Display\',serif; font-size:2.4rem; line-height:1; color:#e67e22; margin-bottom:.2rem; }
  .kpi-lbl { font-size:.65rem; color:rgba(240,237,230,.5); text-transform:uppercase; letter-spacing:.1em; font-family:\'Space Mono\',monospace; }
  .sec-label { font-family:\'Space Mono\',monospace; font-size:.6rem; letter-spacing:.2em; text-transform:uppercase; color:#d4380d; }
  .sec-src { font-family:\'Space Mono\',monospace; font-size:.65rem; color:#8c7355; margin-bottom:1rem; }
  .card { border:1px solid #ede8df !important; border-radius:0 !important; }
  .card-header { background:#1a1612 !important; color:#f0ede6 !important; border-radius:0 !important;
    font-family:\'Space Mono\',monospace; font-size:.68rem; letter-spacing:.1em; text-transform:uppercase; }
  .nav-tabs .nav-link { border-radius:0 !important; font-size:.7rem; letter-spacing:.07em;
    text-transform:uppercase; font-family:\'Space Mono\',monospace; color:#8c7355; }
  .nav-tabs .nav-link.active { color:#1a1612 !important; border-bottom:2px solid #1a1612 !important; font-weight:700; background:transparent !important; }
  table.dataTable thead th { background:#1a1612 !important; color:#f0ede6 !important;
    font-family:\'Space Mono\',monospace; font-size:.62rem; letter-spacing:.1em; text-transform:uppercase; border:none !important; }
  table.dataTable tbody tr:hover td { background:#f5f0e8 !important; }
  .map-chip { display:inline-block; padding:.2rem .55rem; font-size:.62rem; letter-spacing:.07em;
    text-transform:uppercase; cursor:pointer; border-radius:2px; font-weight:700;
    font-family:\'Space Mono\',monospace; margin:2px; }
  .modebar { display:none !important; }
  ::-webkit-scrollbar { width:5px; height:5px; }
  ::-webkit-scrollbar-thumb { background:#d4c9b5; }
"

# ============================================================
#  HELPERS
# ============================================================

pl <- function(p, margin=list(l=10,r=10,t=25,b=45)) {
  p |> layout(plot_bgcolor="#ffffff", paper_bgcolor="#ffffff",
              font=list(family="DM Sans",color="#2d2520",size=12), margin=margin)
}

bar_pal <- function(n) colorRampPalette(c("#f5cba7","#e67e22","#d4380d","#7b241c"))(n)

ob_col <- function(v) dplyr::case_when(
  v>=34~"#922b21", v>=30~"#d4380d", v>=26~"#e67e22", TRUE~"#27ae60"
)

sec_hdr <- function(label, title, src=NULL) {
  tagList(
    div(class="sec-label", label),
    tags$h4(title, style="letter-spacing:-.02em;margin-bottom:.2rem;"),
    if (!is.null(src)) div(class="sec-src", src)
    else tags$hr(style="border-color:#2d2520;margin:.4rem 0 1rem;")
  )
}

get_chain_color <- function(name) {
  col <- CHAIN_COLORS[name]
  ifelse(is.na(col), "#888888", col)
}

