    br(),
    sec_hdr("Raw Data","Browse & Download All Datasets"),
    layout_sidebar(sidebar=sidebar(width=210,
      selectInput("dat_choice","Dataset:",choices=c(
        "Chains (full)"="chains","Nutrition"="nutrition","Obesity"="obesity",
        "Poverty"="poverty","FF by State"="ff_state","Chain Counts"="chain_cts",
        "Race by State"="race","Map Locations (sample)"="map_sample")),
      br(),
      downloadButton("dl","Download CSV",
        style="border-radius:0;background:#1a1612;color:#f0ede6;border:none;
               font-family:\'Space Mono\',monospace;font-size:.68rem;width:100%;")
    ),
    card(full_screen=TRUE,card_body(padding=0,DTOutput("dat_tbl",height="600px"))))
  )
)

# ============================================================
#  SERVER
# ============================================================

server <- function(input, output, session) {

  # ── MAP REACTIVE STATE ────────────────────────────────────
  active_chains <- reactiveVal(TOP_CHAINS)
  clicked_state <- reactiveVal(NULL)

  norm_name <- function(n) {
    n <- gsub("^McDonalds$", "McDonald\'s", n)
    n <- gsub("^Sonic Drive-In$", "SONIC Drive In", n)
    n
  }

  locs_clean <- reactive({
    MAP_LOCS_RAW |> dplyr::mutate(name = norm_name(name))
  })

  filtered_locs <- reactive({
    chains <- active_chains()
    locs   <- locs_clean()
    if (length(chains) > 0) dplyr::filter(locs, name %in% chains) else locs
  })

  # ── MAP CHAIN BUTTONS ─────────────────────────────────────
  output$map_chain_btns <- renderUI({
    btns <- lapply(TOP_CHAINS, function(chain) {
      col      <- get_chain_color(chain)
      is_active <- chain %in% active_chains()
      bg_style  <- if (is_active) paste0("background:",col,"22;color:",col,";border-color:",col,";")
                   else "background:transparent;color:#bbb;border-color:#ddd;"
      tags$button(
        class   = "map-chip",
        style   = paste0("border:1.5px solid;", bg_style),
        onclick = paste0("Shiny.setInputValue(\'chain_toggle_btn\',\'", chain, "\',{priority:\'event\'})"),
        tags$span(style=paste0("display:inline-block;width:7px;height:7px;border-radius:50%;background:",
          if(is_active) col else "#ccc",";margin-right:4px;vertical-align:middle;")),
        chain
      )
    })
    do.call(tagList, btns)
  })

  observeEvent(input$chain_toggle_btn, {
    chain <- input$chain_toggle_btn
    cur   <- active_chains()
    if (chain %in% cur) active_chains(setdiff(cur, chain))
    else                active_chains(union(cur, chain))
  })

  output$map_count <- renderText({
    paste0(format(nrow(filtered_locs()), big.mark=","), " shown")
  })

  # ── BASE MAP ──────────────────────────────────────────────
  output$main_map <- renderLeaflet({
    leaflet(options=leafletOptions(minZoom=3)) |>
      addProviderTiles(providers$CartoDB.Positron,
        options=tileOptions(maxZoom=18)) |>
      setView(lng=-96, lat=38.5, zoom=4) |>
      addScaleBar(position="bottomleft")
  })

  # ── UPDATE MARKERS ────────────────────────────────────────
  observeEvent(list(filtered_locs(), input$map_cluster), {
    locs  <- filtered_locs()
    proxy <- leafletProxy("main_map", session) |>
      clearMarkers() |> clearMarkerClusters()
    if (nrow(locs) == 0) return()

    locs <- locs |> dplyr::mutate(
      color = sapply(name, get_chain_color),
      popup = paste0(
        "<div style=\'font-family:DM Sans,sans-serif;\'>",
        "<strong>", name, "</strong><br>",
        "<span style=\'color:#8c7355;font-size:.8rem;\'>",
        city, ifelse(state != "", paste0(", ", state), ""),
        "</span></div>"
      )
    )

    if (input$map_cluster == "cluster") {
      for (chain in unique(locs$name)) {
        sub <- dplyr::filter(locs, name == chain)
        col <- get_chain_color(chain)
        proxy <- proxy |> addCircleMarkers(
          data=sub, lng=~lng, lat=~lat, popup=~popup,
          radius=5, fillColor=col, fillOpacity=0.85,
          color="rgba(0,0,0,0.2)", weight=0.5,
          clusterOptions=markerClusterOptions(
            iconCreateFunction=JS(sprintf(
              "function(c){var n=c.getChildCount(),s=n>100?44:n>20?34:26;
               return L.divIcon({html:\'<div style=\"background:%s;color:white;
               border-radius:50%%;width:\'+s+\'px;height:\'+s+\'px;display:flex;
               align-items:center;justify-content:center;font-family:Space Mono,monospace;
               font-size:10px;font-weight:700;border:2px solid white;
               box-shadow:0 1px 4px rgba(0,0,0,.3)\">\'+ n +\'</div>\',
               className:\'\',iconSize:L.point(s,s)});}", col))
          )
        )
      }
    } else {
      proxy |> addCircleMarkers(
        data=locs, lng=~lng, lat=~lat, popup=~popup,
        radius=4, fillColor=~color, fillOpacity=0.82,
        color="rgba(0,0,0,0.15)", weight=0.5
      )
    }
  }, ignoreInit=FALSE)

  # ── STATE OVERLAY ─────────────────────────────────────────
  observeEvent(input$map_overlay, {
    proxy <- leafletProxy("main_map", session) |> clearShapes()
    leafletProxy("main_map", session) |>
      removeControl("overlay_legend")
    if (input$map_overlay == "none") return()

    tryCatch({
      geo_url <- "https://raw.githubusercontent.com/PublicaMundi/MappingAPI/master/data/geojson/us-states.json"
      states_sf <- geojsonsf::geojson_sf(geo_url)

      if (input$map_overlay == "obesity") {
        merged <- dplyr::left_join(states_sf, OBESITY_DATA, by=c("name"="state"))
        pal    <- colorNumeric(c("#27ae60","#f39c12","#e67e22","#d4380d","#922b21"),
                               domain=c(18,40), na.color="transparent")
        proxy |>
          addPolygons(data=merged, fillColor=~pal(obesity_pct), fillOpacity=0.35,
            color="rgba(0,0,0,.15)", weight=1, layerId=~name,
            label=~paste0(name, ": ", obesity_pct, "% obesity"),
            highlightOptions=highlightOptions(weight=2,color="#1a1612",
              fillOpacity=0.55, bringToFront=TRUE)) |>
          addLegend("bottomright", pal=pal, values=merged$obesity_pct,
            title="Obesity (%)", opacity=0.9, layerId="overlay_legend")
      } else {
        merged <- dplyr::left_join(states_sf, POVERTY_DATA, by=c("name"="state"))
        pal    <- colorNumeric(c("#16a085","#2980b9","#2c3e50","#8e44ad","#6c3483"),
                               domain=c(5,16), na.color="transparent")
        proxy |>
          addPolygons(data=merged, fillColor=~pal(poverty_pct), fillOpacity=0.35,
            color="rgba(0,0,0,.15)", weight=1, layerId=~name,
            label=~paste0(name, ": ", poverty_pct, "% poverty"),
            highlightOptions=highlightOptions(weight=2,color="#1a1612",
              fillOpacity=0.55, bringToFront=TRUE)) |>
          addLegend("bottomright", pal=pal, values=merged$poverty_pct,
            title="Poverty (%)", opacity=0.9, layerId="overlay_legend")
      }
    }, error=function(e) {
      showNotification(
        "Install geojsonsf for state overlays: install.packages(\'geojsonsf\')",
        type="warning", duration=8)
    })
  })

  # ── STATE CLICK INFO ──────────────────────────────────────
  observeEvent(input$main_map_shape_click, {
    clicked_state(input$main_map_shape_click$id)
  })

  output$state_info_panel <- renderUI({
    sname <- clicked_state()
    if (is.null(sname)) return(NULL)

    abbr_map <- c(Alabama="AL",Alaska="AK",Arizona="AZ",Arkansas="AR",California="CA",
      Colorado="CO",Connecticut="CT",Delaware="DE",Florida="FL",Georgia="GA",
      Hawaii="HI",Idaho="ID",Illinois="IL",Indiana="IN",Iowa="IA",Kansas="KS",
      Kentucky="KY",Louisiana="LA",Maine="ME",Maryland="MD",Massachusetts="MA",
      Michigan="MI",Minnesota="MN",Mississippi="MS",Missouri="MO",Montana="MT",
      Nebraska="NE",Nevada="NV",`New Hampshire`="NH",`New Jersey`="NJ",
      `New Mexico`="NM",`New York`="NY",`North Carolina`="NC",`North Dakota`="ND",
      Ohio="OH",Oklahoma="OK",Oregon="OR",Pennsylvania="PA",`Rhode Island`="RI",
      `South Carolina`="SC",`South Dakota`="SD",Tennessee="TN",Texas="TX",
      Utah="UT",Vermont="VT",Virginia="VA",Washington="WA",`West Virginia`="WV",
      Wisconsin="WI",Wyoming="WY",`District of Columbia`="DC")

    abbr       <- abbr_map[sname]
    state_locs <- dplyr::filter(locs_clean(), state %in% c(abbr, sname))
    top5       <- state_locs |> dplyr::count(name, sort=TRUE) |> dplyr::slice_head(n=5)
    ob_row     <- dplyr::filter(OBESITY_DATA, state == sname)
    pov_row    <- dplyr::filter(POVERTY_DATA, state == sname)

    div(style="border:1px solid #ede8df;border-left:4px solid #d4380d;
               background:white;padding:1rem 1.4rem;margin-top:.5rem;",
      div(style="display:flex;gap:2.5rem;flex-wrap:wrap;",
        div(
          tags$h5(paste0("📍 ", sname),
            style="font-family:\'DM Serif Display\',serif;font-size:1.3rem;margin-bottom:.4rem;"),
          if (nrow(ob_row)>0)
            p(tags$strong(paste0(ob_row$obesity_pct[1], "%"),
              style="font-family:\'Space Mono\',monospace;"),
              " adult obesity rate", style="font-size:.82rem;margin-bottom:.2rem;"),
          if (nrow(pov_row)>0)
            p(tags$strong(paste0(pov_row$poverty_pct[1], "%"),
              style="font-family:\'Space Mono\',monospace;"),
              " poverty rate", style="font-size:.82rem;")
        ),
        div(
          p("Top chains:", style="font-family:\'Space Mono\',monospace;font-size:.62rem;
              color:#8c7355;text-transform:uppercase;letter-spacing:.1em;margin-bottom:.4rem;"),
          tagList(lapply(seq_len(nrow(top5)), function(i) {
            col <- get_chain_color(top5$name[i])
            p(tags$span(style=paste0("display:inline-block;width:8px;height:8px;",
                "border-radius:50%;background:",col,";margin-right:5px;")),
              tags$strong(top5$name[i]),
              paste0(" — ", top5$n[i], " locations"),
              style="font-size:.78rem;margin-bottom:.15rem;")
          })),
          p(paste0("Total in dataset: ", nrow(state_locs)),
            style="font-size:.7rem;color:#8c7355;font-family:\'Space Mono\',monospace;margin-top:.3rem;")
        )
      )
    )
  })

  # ── MAP LEGEND ────────────────────────────────────────────
  output$map_legend_ui <- renderUI({
    div(style="display:flex;flex-wrap:wrap;gap:.5rem;padding:.7rem;
               background:white;border:1px solid #ede8df;",
      lapply(TOP_CHAINS, function(chain) {
        col <- get_chain_color(chain)
        tags$span(style="display:flex;align-items:center;gap:4px;
                         font-size:.62rem;font-family:\'Space Mono\',monospace;",
          tags$span(style=paste0("width:9px;height:9px;border-radius:50%;",
            "background:",col,";display:inline-block;")),
          chain)
      })
    )
  })

  # ── CHAINS ────────────────────────────────────────────────
  output$chains_bar <- renderPlotly({
    df <- CHAINS_FULL |>
      arrange(desc(.data[[input$chain_sort]])) |>
      slice_head(n=input$n_chains) |>
      mutate(name=fct_reorder(name, .data[[input$chain_sort]]))
    plot_ly(df,x=~.data[[input$chain_sort]],y=~name,type="bar",orientation="h",
            marker=list(color=bar_pal(nrow(df))),
            hovertemplate="<b>%{y}</b><br>%{x:,.0f}<extra></extra>") |>
      layout(xaxis=list(title=input$chain_sort,gridcolor="#ede8df",zeroline=FALSE),
             yaxis=list(title="")) |> pl()
  })

  output$chains_bubble <- renderPlotly({
    plot_ly(CHAINS_FULL,x=~units,y=~sales,size=~sales,text=~name,
            type="scatter",mode="markers",
            marker=list(sizemode="area",sizeref=2*max(CHAINS_FULL$sales)/(60^2),
              color=~sales,colorscale=list(c(0,"#f5cba7"),c(0.5,"#e67e22"),c(1,"#7b241c")),
              showscale=TRUE,opacity=0.85,line=list(color="white",width=1)),
            hovertemplate="<b>%{text}</b><br>Units: %{x:,}<br>Sales: $%{y:,.0f}M<extra></extra>") |>
      layout(xaxis=list(title="Total Units",gridcolor="#ede8df"),
             yaxis=list(title="Sales ($M)",gridcolor="#ede8df"),showlegend=FALSE) |>
      pl(margin=list(l=10,r=80,t=25,b=50))
  })

  output$chains_table <- renderDT({
    CHAINS_FULL |>
      mutate(sales=paste0("$",comma(sales),"M"),avg_unit=paste0("$",comma(avg_unit),"K"),
             units=comma(units),franchised=comma(franchised),company=comma(company),
             change=ifelse(change>=0,paste0("+",change),as.character(change))) |>
      rename(Chain=name,`Sales`=sales,`Avg/Unit`=avg_unit,Franchised=franchised,
             Company=company,`Total Units`=units,`Change`=change) |>
      datatable(rownames=FALSE,options=list(pageLength=20,dom="ftip",scrollX=TRUE),class="compact stripe") |>
      formatStyle("Change",color=styleInterval(0,c("#c0392b","#27ae60")),fontWeight="bold")
  })

  # ── NUTRITION ─────────────────────────────────────────────
  make_nbar <- function(metric, hi="#d4380d", lo="#27ae60", sfx="") {
    df <- NUTRITION |> arrange(desc(.data[[metric]])) |>
      mutate(restaurant=fct_inorder(restaurant),
             color=ifelse(.data[[metric]]>=median(.data[[metric]]),hi,lo))
    plot_ly(df,x=~.data[[metric]],y=~restaurant,type="bar",orientation="h",
            marker=list(color=~color),
            hovertemplate=paste0("<b>%{y}</b><br>",metric,": %{x:.1f}",sfx,"<extra></extra>")) |>
      layout(xaxis=list(title=paste(metric,sfx),gridcolor="#ede8df",zeroline=FALSE),
             yaxis=list(title=""),showlegend=FALSE) |> pl()
  }
  output$cal_bar  <- renderPlotly(make_nbar("calories"))
  output$sod_bar  <- renderPlotly(make_nbar("sodium","#922b21","#16a085","mg"))
  output$fat_bar  <- renderPlotly(make_nbar("total_fat","#d4380d","#27ae60","g"))
  output$prot_bar <- renderPlotly(make_nbar("protein","#27ae60","#2980b9","g"))

  output$nutr_heat <- renderPlotly({
    metrics <- c("calories","sodium","total_fat","protein","sugar")
    mat <- NUTRITION |> select(all_of(metrics)) |>
      mutate(across(everything(),~(.x-min(.x))/(max(.x)-min(.x)+1e-9)))
    plot_ly(x=c("Calories","Sodium","Fat","Protein","Sugar"),y=NUTRITION$restaurant,
            z=as.matrix(mat),type="heatmap",
            colorscale=list(c(0,"#f9f3e8"),c(0.5,"#e67e22"),c(1,"#7b241c")),
            hovertemplate="<b>%{y}</b> — %{x}: %{z:.2f}<extra></extra>") |>
      layout(xaxis=list(title="",tickangle=-20),yaxis=list(title="")) |>
      pl(margin=list(l=10,r=80,t=25,b=60))
  })

  output$nutr_sc <- renderPlotly({
    pal <- c("#e8a000","#dd0031","#7b2d8b","#c0392b","#8b2500","#00437a","#009a44","#e67e22")
    plot_ly(NUTRITION,x=~.data[[input$sc_x]],y=~.data[[input$sc_y]],
            color=~restaurant,colors=pal,type="scatter",mode="markers",text=~restaurant,
            marker=list(size=14,opacity=0.85,line=list(color="white",width=1.5)),
            hovertemplate="<b>%{text}</b><br>%{x:.1f} / %{y:.1f}<extra></extra>") |>
      layout(xaxis=list(title=input$sc_x,gridcolor="#ede8df"),
             yaxis=list(title=input$sc_y,gridcolor="#ede8df"),
             legend=list(orientation="h",y=-0.22)) |>
      pl(margin=list(l=10,r=10,t=25,b=90))
  })

  output$nutr_tbl <- renderDT(
    datatable(NUTRITION,rownames=FALSE,filter="top",
              options=list(pageLength=10,dom="ftip"),class="compact stripe")
  )

  # ── OBESITY ───────────────────────────────────────────────
  output$ob_dot <- renderPlotly({
    df <- OBESITY |> arrange(desc(obesity_pct)) |>
      mutate(state=fct_inorder(state),color=ob_col(obesity_pct))
    plot_ly(df) |>
      add_segments(x=18,xend=~obesity_pct,y=~state,yend=~state,
                   line=list(color="rgba(0,0,0,.07)",width=1)) |>
      add_markers(x=~obesity_pct,y=~state,
                  marker=list(color=~color,size=10,line=list(color="white",width=1.5)),
                  text=~paste0(state,": ",obesity_pct,"%"),hoverinfo="text") |>
      layout(xaxis=list(title="Obesity Rate (%)",range=c(18,39),gridcolor="#ede8df"),
             yaxis=list(title="",tickfont=list(size=10)),showlegend=FALSE) |>
      pl(margin=list(l=10,r=10,t=10,b=40))
  })

  output$ob_hist <- renderPlotly({
    plot_ly(OBESITY,x=~obesity_pct,type="histogram",nbinsx=12,
            marker=list(color="#d4380d",line=list(color="white",width=0.8))) |>
      layout(xaxis=list(title="Obesity Rate (%)",gridcolor="#ede8df"),
             yaxis=list(title="States",gridcolor="#ede8df")) |>
      pl(margin=list(l=10,r=10,t=5,b=40))
  })

  output$ob_box <- renderPlotly({
    plot_ly(OBESITY,x=~obesity_pct,type="box",
            marker=list(color="#d4380d",size=4),line=list(color="#922b21"),
            fillcolor="rgba(212,56,13,0.15)") |>
      layout(xaxis=list(title="Obesity Rate (%)",gridcolor="#ede8df"),
             yaxis=list(showticklabels=FALSE)) |>
      pl(margin=list(l=10,r=10,t=5,b=40))
  })

  output$pov_bar <- renderPlotly({
    df <- POVERTY |> arrange(desc(poverty_pct)) |>
      mutate(state=fct_inorder(state),
             color=dplyr::case_when(poverty_pct>=13~"#6c3483",poverty_pct>=11~"#8e44ad",
               poverty_pct>=9~"#2c3e50",poverty_pct>=7~"#2980b9",TRUE~"#16a085"))
    plot_ly(df,x=~poverty_pct,y=~state,type="bar",orientation="h",
            marker=list(color=~color),
            hovertemplate="<b>%{y}</b><br>%{x:.1f}%<extra></extra>") |>
      layout(xaxis=list(title="Poverty Rate (%)",gridcolor="#ede8df"),
             yaxis=list(title="",tickfont=list(size=10))) |> pl()
  })

  output$pov_ob_sc <- renderPlotly({
    df <- dplyr::inner_join(POVERTY,OBESITY,by="state") |>
      mutate(color=ob_col(obesity_pct))
    cor_v <- round(cor(df$poverty_pct,df$obesity_pct),2)
    plot_ly(df,x=~poverty_pct,y=~obesity_pct,type="scatter",mode="markers+text",
            text=~state,textposition="top right",textfont=list(size=8,color="#8c7355"),
            marker=list(color=~color,size=9,opacity=0.85),
            hovertemplate="<b>%{text}</b><br>Pov:%{x:.1f}% Ob:%{y:.1f}%<extra></extra>") |>
      layout(title=list(text=paste0("r = ",cor_v),font=list(size=11,color="#8c7355"),x=0.01),
             xaxis=list(title="Poverty (%)",gridcolor="#ede8df"),
             yaxis=list(title="Obesity (%)",gridcolor="#ede8df"),showlegend=FALSE) |>
      pl(margin=list(l=20,r=20,t=35,b=50))
  })

  output$st_gauge <- renderPlotly({
    req(input$state_pick)
    ob_v  <- dplyr::filter(OBESITY,state==input$state_pick)$obesity_pct
    pov_v <- dplyr::filter(POVERTY,state==input$state_pick)$poverty_pct
    ob_v  <- if(length(ob_v)>0)  ob_v[1]  else mean(OBESITY$obesity_pct)
    pov_v <- if(length(pov_v)>0) pov_v[1] else mean(POVERTY$poverty_pct)
    plot_ly() |>
      add_trace(type="indicator",mode="gauge+number+delta",value=ob_v,
        title=list(text="Obesity (%)"),
        delta=list(reference=mean(OBESITY$obesity_pct),valueformat=".1f",
                   increasing=list(color="#c0392b"),decreasing=list(color="#27ae60")),
        gauge=list(axis=list(range=list(18,40)),bar=list(color="#d4380d"),
          threshold=list(line=list(color="#2d2520",width=2),thickness=0.75,value=mean(OBESITY$obesity_pct))),
        domain=list(x=c(0,1),y=c(0.52,1))) |>
      add_trace(type="indicator",mode="gauge+number+delta",value=pov_v,
        title=list(text="Poverty (%)"),
        delta=list(reference=mean(POVERTY$poverty_pct),valueformat=".1f",
                   increasing=list(color="#c0392b"),decreasing=list(color="#27ae60")),
        gauge=list(axis=list(range=list(0,16)),bar=list(color="#8e44ad"),
          threshold=list(line=list(color="#2d2520",width=2),thickness=0.75,value=mean(POVERTY$poverty_pct))),
        domain=list(x=c(0,1),y=c(0,0.45))) |>
      layout(plot_bgcolor="#ffffff",paper_bgcolor="#ffffff",
             font=list(family="DM Sans",color="#2d2520"),margin=list(l=10,r=10,t=10,b=10))
  })

  output$st_peer <- renderPlotly({
    req(input$state_pick)
    df <- OBESITY |> arrange(desc(obesity_pct)) |> slice_head(n=20) |>
      mutate(color=ifelse(state==input$state_pick,"#d4380d","#d4c9b5"),state=fct_inorder(state))
    plot_ly(df,x=~obesity_pct,y=~state,type="bar",orientation="h",marker=list(color=~color),
            hovertemplate="<b>%{y}</b>: %{x:.1f}%<extra></extra>") |>
      layout(xaxis=list(title="Obesity (%)",gridcolor="#ede8df"),
             yaxis=list(title="",tickfont=list(size=10))) |> pl()
  })

  # ── DEMOGRAPHICS ──────────────────────────────────────────
  output$us_pie <- renderPlotly({
    plot_ly(RACE_US,labels=~group,values=~pct,type="pie",
            marker=list(colors=c("#4e9af1","#54c066","#e87040","#f0c040","#94a3b8"),
                        line=list(color="white",width=2)),
            textinfo="label+percent",
            hovertemplate="<b>%{label}</b>: %{percent}<extra></extra>") |>
      layout(showlegend=FALSE,plot_bgcolor="#ffffff",paper_bgcolor="#ffffff",
             font=list(family="DM Sans",color="#2d2520",size=11),
             margin=list(l=10,r=10,t=10,b=10))
  })

  output$ff_state <- renderPlotly({
    df <- FF_BY_STATE |> arrange(desc(count)) |> mutate(state=fct_inorder(state))
    plot_ly(df,x=~count,y=~state,type="bar",orientation="h",
            marker=list(color=bar_pal(nrow(df))),
            hovertemplate="<b>%{y}</b>: %{x:,}<extra></extra>") |>
      layout(xaxis=list(title="Locations",gridcolor="#ede8df"),yaxis=list(title="")) |> pl()
  })

  output$race_stack <- renderPlotly({
    df <- dplyr::filter(RACE_STATES, state != "United States")
    if (input$race_sort) df <- df |> arrange(white)
    df <- df |> mutate(state=fct_inorder(state))
    grps   <- input$race_grps
    labels <- c(white="White",black="Black",hispanic="Hispanic",asian="Asian")
    colors <- c(white="#4e9af1",black="#e87040",hispanic="#54c066",asian="#f0c040")
    p <- plot_ly()
    for (g in grps) {
      p <- p |> add_trace(x=df[[g]]*100,y=df$state,type="bar",orientation="h",
        name=labels[g],marker=list(color=colors[g]),
        hovertemplate=paste0("<b>%{y}</b><br>",labels[g],": %{x:.1f}%<extra></extra>"))
    }
    p |> layout(barmode="stack",
                xaxis=list(title="Population Share (%)"),yaxis=list(title="",tickfont=list(size=9)),
                legend=list(orientation="h",y=-0.05)) |>
      pl(margin=list(l=10,r=10,t=10,b=70))
  })

  output$chain_cts <- renderPlotly({
    df <- CHAIN_COUNTS |> arrange(desc(count)) |> mutate(chain=fct_inorder(chain))
    plot_ly(df,x=~count,y=~chain,type="bar",orientation="h",
            marker=list(color=bar_pal(nrow(df))),
            hovertemplate="<b>%{y}</b>: %{x:,}<extra></extra>") |>
      layout(xaxis=list(title="Locations",gridcolor="#ede8df"),yaxis=list(title="")) |> pl()
  })

  # ── DATA EXPLORER ─────────────────────────────────────────
  cur_dat <- reactive({
    switch(input$dat_choice,
      chains     = CHAINS_FULL,
      nutrition  = NUTRITION,
      obesity    = OBESITY,
      poverty    = POVERTY,
      ff_state   = FF_BY_STATE,
      chain_cts  = CHAIN_COUNTS,
      race       = RACE_STATES,
      map_sample = head(MAP_LOCS_RAW, 500)
    )
  })

  output$dat_tbl <- renderDT(
    datatable(cur_dat(),rownames=FALSE,filter="top",
              options=list(pageLength=25,dom="ftip",scrollX=TRUE),class="compact stripe")
  )

  output$dl <- downloadHandler(
    filename = function() paste0(input$dat_choice,"_data.csv"),
    content  = function(f) write.csv(cur_dat(), f, row.names=FALSE)
  )
}

# ============================================================
shinyApp(ui, server)
